import os

# Function to process volatility data
def count_high_vol_days(data):
    count = 0
    for row in data:
        try:
            high = float(row['High'])
            low = float(row['Low'])
            if low > 0:
                pct_range = ((high - low) / low) * 100
                if pct_range > 20:
                    count += 1
        except:
            continue
    return count

# Get the BOSC data
bosc_file = locals()['var_functions.query_db:62']
if isinstance(bosc_file, str):
    with open(bosc_file, 'r') as f:
        bosc_data = json.load(f)
else:
    bosc_data = bosc_file

# Count high vol days for BOSC
count_bosc = count_high_vol_days(bosc_data)
print('BOSC: ' + str(count_bosc) + ' high volatility days')

# Get the complete results so far
results_file = locals()['var_functions.execute_python:60']
if isinstance(results_file, str):
    with open(results_file, 'r') as f:
        prev_results = json.load(f)
else:
    prev_results = results_file

all_counts = prev_results['all_counts']
all_counts['BOSC'] = count_bosc

print('Current top rankings:')
sorted_stocks = sorted(all_counts.items(), key=lambda x: x[1], reverse=True)
for i, (symbol, count) in enumerate(sorted_stocks[:10], 1):
